using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiFetchTool> logger,
        [Description("The API path to fetch (e.g. \"/users/1\").")] string path)
    {
        logger.LogInformation("Fetching external API: {Path}", path);

        var client = httpClientFactory.CreateClient("ExternalApi");

        try
        {
            var response = await client.GetAsync(path);
            response.EnsureSuccessStatusCode();
            var content = await response.Content.ReadAsStringAsync();

            logger.LogInformation("API call succeeded for {Path}", path);
            return content;
        }
        catch (HttpRequestException ex)
        {
            logger.LogError(ex, "API call failed for {Path}", path);
            return $"Error fetching {path}: {ex.Message}";
        }
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt, Description("Generates a prompt for summarizing text content.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text content to summarize.")] string content,
        [Description("Desired summary style: brief, detailed, or bullet-points.")] string style = "brief")
    {
        yield return new ChatMessage(
            ChatRole.User,
            $"""
            Please summarize the following content in a {style} style.

            Content:
            {content}
            """);
    }
}

